import{_ as e,o as l,c as a,a2 as r}from"./chunks/framework.BQ1gajhD.js";const f=JSON.parse('{"title":"北海公园","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/beihai/index.md","filePath":"landmarks/beihai/index.md","lastUpdated":1784720050000}'),n={name:"landmarks/beihai/index.md"};function d(s,t,i,o,g,h){return l(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="北海公园" tabindex="-1">北海公园 <a class="header-anchor" href="#北海公园" aria-label="Permalink to &quot;北海公园&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1768109027865-f5b57609fabd?w=1200&amp;q=80" alt="北海公园白塔"></p><blockquote><p>&quot;让我们荡起双桨，小船儿推开波浪，海面倒映着美丽的白塔……&quot; 一首唱了七十年的歌，唱的就是这里。</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>北海公园位于北京市中心，故宫西北、景山以西，是中国现存<strong>建园最早、保存最完整、历史最悠久的皇家园林之一</strong>。它的历史可上溯至<strong>辽代</strong>（约公元10世纪），此后历经<strong>辽、金、元、明、清五个朝代近千年</strong>的营建与修缮，园址从未迁移、格局绵延不绝，堪称一部活着的中国皇家园林史。</p><p>整座园林以太液池（北海）为中心，以池中<strong>琼华岛</strong>及其山顶的<strong>白塔</strong>为视觉核心，环湖布置团城、北岸、东岸诸景。辽金时此处为帝王离宫别苑，元代忽必烈以琼华岛为中心营建大都、将此地圈入皇城；明清两代成为禁苑，称&quot;西苑&quot;。1925年北海正式辟为公园向公众开放，1961年被列为第一批全国重点文物保护单位。</p><p>登琼华岛而四望，南可望故宫角楼与中南海，北可眺景山万春亭，红墙金瓦与碧水白塔相映，是北京城中最具诗意的古典园林空间。</p><table tabindex="0"><thead><tr><th style="text-align:left;">朝代</th><th style="text-align:left;">大事</th></tr></thead><tbody><tr><td style="text-align:left;">辽代</td><td style="text-align:left;">始建离宫别苑，为园林之肇始</td></tr><tr><td style="text-align:left;">金代</td><td style="text-align:left;">扩建为皇家苑囿&quot;太宁宫&quot;</td></tr><tr><td style="text-align:left;">元代</td><td style="text-align:left;">忽必烈以琼华岛为中心营建大都，圈入皇城</td></tr><tr><td style="text-align:left;">明清</td><td style="text-align:left;">成为皇家禁苑&quot;西苑&quot;，营建白塔、九龙壁、五龙亭诸景</td></tr><tr><td style="text-align:left;">1925年</td><td style="text-align:left;">正式辟为北海公园，向公众开放</td></tr><tr><td style="text-align:left;">1961年</td><td style="text-align:left;">列为第一批全国重点文物保护单位</td></tr></tbody></table><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">旺季（4-10月）6:00-21:00；淡季（11-3月）6:30-20:00</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">门票10元；联票20元（含琼华岛、团城）</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁6号线北海北站下车即到（北门进）</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">经典2-3小时 / 深度4小时</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">四季皆宜，夏季赏荷、秋季银杏最佳</td></tr></tbody></table><h2 id="子景点导览" tabindex="-1">子景点导览 <a class="header-anchor" href="#子景点导览" aria-label="Permalink to &quot;子景点导览&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:left;">看点</th><th style="text-align:center;">建议时长</th></tr></thead><tbody><tr><td style="text-align:left;"><a href="/beijing-travel-guide/landmarks/beihai/baita.html">白塔与琼华岛</a></td><td style="text-align:left;">全园标志，35.9米藏式白塔，登岛俯瞰故宫景山</td><td style="text-align:center;">1-1.5小时</td></tr><tr><td style="text-align:left;"><a href="/beijing-travel-guide/landmarks/beihai/jiulongbi.html">九龙壁</a></td><td style="text-align:left;">中国三大九龙壁之一，七色琉璃、双面九龙</td><td style="text-align:center;">15-20分钟</td></tr><tr><td style="text-align:left;"><a href="/beijing-travel-guide/landmarks/beihai/wulongting.html">五龙亭</a></td><td style="text-align:left;">北岸五亭凌波，皇帝垂钓赏焰火之地</td><td style="text-align:center;">20-30分钟</td></tr><tr><td style="text-align:left;"><a href="/beijing-travel-guide/landmarks/beihai/tuancheng.html">团城</a></td><td style="text-align:left;">圆形城台，白玉佛与元代渎山大玉海</td><td style="text-align:center;">40-60分钟</td></tr><tr><td style="text-align:left;"><a href="/beijing-travel-guide/landmarks/beihai/jingxinzhai.html">静心斋</a></td><td style="text-align:left;">&quot;乾隆小花园&quot;，保存最完整的园中之园</td><td style="text-align:center;">40分钟</td></tr><tr><td style="text-align:left;"><a href="/beijing-travel-guide/landmarks/beihai/xitianfanjing.html">西天梵境</a></td><td style="text-align:left;">大慈真如宝殿全金丝楠木，藏传佛教建筑群</td><td style="text-align:center;">30-40分钟</td></tr></tbody></table><h2 id="推荐游览路线" tabindex="-1">推荐游览路线 <a class="header-anchor" href="#推荐游览路线" aria-label="Permalink to &quot;推荐游览路线&quot;">​</a></h2><h3 id="🕐-经典游-2-3小时-精华速览" tabindex="-1">🕐 经典游（2-3小时，精华速览） <a class="header-anchor" href="#🕐-经典游-2-3小时-精华速览" aria-label="Permalink to &quot;🕐 经典游（2-3小时，精华速览）&quot;">​</a></h3><p>南门进园，直奔核心，不走回头路：</p><blockquote><p><strong>南门</strong> → <strong>团城</strong>（看白玉佛与渎山大玉海）→ 过永安桥登<strong>琼华岛</strong> → <strong>永安寺</strong> → 登<strong>白塔</strong>俯瞰全园 → 下山环岛 → 沿东岸北行 → <strong>九龙壁</strong> → <strong>五龙亭</strong> → <strong>北门</strong>出</p></blockquote><p>这条路线串联了白塔、团城、九龙壁、五龙亭四大标志性景观，是初访者的首选。出北门即地铁6号线北海北站，交通极便。</p><h3 id="🗓️-深度游-约4小时-尽览全园" tabindex="-1">🗓️ 深度游（约4小时，尽览全园） <a class="header-anchor" href="#🗓️-深度游-约4小时-尽览全园" aria-label="Permalink to &quot;🗓️ 深度游（约4小时，尽览全园）&quot;">​</a></h3><p>上午走北岸人文精华，下午登岛览胜：</p><blockquote><p>上午：<strong>北门</strong> → <strong>静心斋</strong>（乾隆小花园）→ <strong>西天梵境</strong>（金丝楠木大殿）→ <strong>九龙壁</strong> → <strong>五龙亭</strong> 下午：<strong>团城</strong> → <strong>琼华岛</strong>（永安寺、白塔、琼岛春阴碑、阅古楼）→ 沿东岸漫步濠濮间、画舫斋 → 南门或东门出</p></blockquote><p>深度路线可从容品味北岸的园林与宗教建筑精华，再登岛俯瞰全城，适合时间充裕、喜爱古建的游客。</p><h2 id="文化故事-让我们荡起双桨" tabindex="-1">文化故事：让我们荡起双桨 <a class="header-anchor" href="#文化故事-让我们荡起双桨" aria-label="Permalink to &quot;文化故事：让我们荡起双桨&quot;">​</a></h2><p>1955年，长春电影制片厂拍摄了新中国第一部儿童题材影片**《祖国的花朵》<strong>，片中孩子们在北海划船的镜头，正是取景于北海公园的太液池。影片主题曲</strong>《让我们荡起双桨》**由乔羽作词、刘炽作曲，&quot;海面倒映着美丽的白塔，四周环绕着绿树红墙&quot;——歌词里写的正是琼华岛白塔与环湖的宫墙绿树。这首歌从此传唱大江南北，成为几代中国人的共同记忆。如今在北海划船，望着水中的白塔倒影，仍能体会到当年那份纯真与诗意。</p><h2 id="四季景色" tabindex="-1">四季景色 <a class="header-anchor" href="#四季景色" aria-label="Permalink to &quot;四季景色&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">季节</th><th style="text-align:left;">景色</th><th style="text-align:left;">最佳时间</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>春</strong></td><td style="text-align:left;">琼岛桃花、海棠争艳，柳丝拂水</td><td style="text-align:left;">3月下旬-4月</td></tr><tr><td style="text-align:left;"><strong>夏</strong></td><td style="text-align:left;">太液池荷花盛放，&quot;让我们荡起双桨&quot;正当时</td><td style="text-align:left;">7月-8月</td></tr><tr><td style="text-align:left;"><strong>秋</strong></td><td style="text-align:left;">北岸银杏金黄，白塔映蓝天</td><td style="text-align:left;">10月下旬-11月</td></tr><tr><td style="text-align:left;"><strong>冬</strong></td><td style="text-align:left;">白塔雪景，湖面结冰可赏冰嬉旧俗</td><td style="text-align:left;">雪后初晴</td></tr></tbody></table><h2 id="划船价格" tabindex="-1">划船价格 <a class="header-anchor" href="#划船价格" aria-label="Permalink to &quot;划船价格&quot;">​</a></h2><p>北海水面开阔，是北京市内最经典的划船胜地之一。码头多设于东岸、南岸及琼华岛周边。</p><table tabindex="0"><thead><tr><th style="text-align:left;">船型</th><th style="text-align:center;">价格（元/小时）</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>手划船</strong></td><td style="text-align:center;">60</td><td style="text-align:left;">传统双人手划，最贴近&quot;荡起双桨&quot;的意境</td></tr><tr><td style="text-align:left;"><strong>脚踏船</strong></td><td style="text-align:center;">80</td><td style="text-align:left;">省力休闲，适合家庭亲子</td></tr><tr><td style="text-align:left;"><strong>电动船</strong></td><td style="text-align:center;">100</td><td style="text-align:left;">轻松惬意，可从容游遍全湖</td></tr></tbody></table><blockquote><p>划船需另付押金（可退），具体价格以现场公示为准；冬季湖面结冰停航。</p></blockquote><h2 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h2><ol><li><strong>联票更划算</strong>：联票20元已含琼华岛与团城，单买琼岛门票反而更贵，建议直接购联票。</li><li><strong>北门进最便</strong>：地铁6号线北海北站紧邻北门，由此进园先游北岸诸景，再登琼华岛，动线顺畅。</li><li><strong>登塔看全景</strong>：琼华岛白塔是俯瞰故宫、景山、中南海的最佳观景点，下午光线尤佳。</li><li><strong>预留划船时间</strong>：若逢晴好天气，留一小时泛舟太液池，从水面回望白塔，是北海最美的视角。</li><li><strong>联游周边</strong>：北海与景山公园仅一街之隔，可安排同日联游，登景山万春亭回望北海白塔。</li></ol><hr><p><strong>📍 地址</strong>：北京市西城区文津街1号 <strong>📞 电话</strong>：010-64040610 <strong>🌐 官网</strong>：<a href="http://www.beihaipark.com.cn" target="_blank" rel="noreferrer">www.beihaipark.com.cn</a></p>',33)])])}const y=e(n,[["render",d]]);export{f as __pageData,y as default};
